// Cleanest, readable
function maxCharMap(str) {
  const freq = new Map();
  for (const char of str) freq.set(char, (freq.get(char) || 0) + 1);
  return Array.from(freq.entries()).reduce((max, [char, count]) =>
    count > max[1] ? [char, count] : max
  );
}

// Fixed alphabet optimization
function maxCharArray(str) {
  const counts = new Uint32Array(128); // ASCII
  for (const char of str) counts[char.charCodeAt(0)]++;
  let maxChar = 0, maxCount = 0;
  for (let i = 0; i < 128; i++) {
    if (counts[i] > maxCount) {
      maxCount = counts[i];
      maxChar = String.fromCharCode(i);
    }
  }
  return maxChar;
}

// One-liner (if reduceOneOf lands)
const maxCharReduce = str =>
  [...str].reduce((acc, char) => ({...acc, [char]: (acc[char] || 0) + 1}), {})
    |> Object.entries() |> maxBy(([_, count]) => count)[0];
